private struct DeliverooTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum DeliverooScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("favour"):
            DeliverooRestaurantsScreen()
        case let t where t.contains("search") || t.contains("recherch"):
            DeliverooSearchScreen()
        case let t where t.contains("account") || t.contains("compte") || t.contains("profil"):
            DeliverooAccountScreen()
        default:
            DeliverooGenericListScreen(title: tab)
        }
    }
}
